 namespace WPAICG\Core\Providers\OpenRouter\Methods; use WP_Error; if (!defined('ABSPATH')) { exit; } function build_logic_for_url_builder(string $operation, array $params): string|WP_Error { $base_url = !empty($params['base_url']) ? rtrim($params['base_url'], '/') : ''; $api_version = !empty($params['api_version']) ? $params['api_version'] : ''; if (empty($base_url)) return new WP_Error("missing_base_url_OpenRouter_logic", __('OpenRouter Base URL is required.', 'gpt3-ai-content-generator')); $paths = [ 'responses' => '/responses', 'models' => '/models', 'embeddings' => '/embeddings', 'embedding_models' => '/embeddings/models', ]; $path_key = ($operation === 'chat' || $operation === 'stream') ? 'responses' : $operation; $path_segment = $paths[$path_key] ?? null; if ($path_segment === null) { return new WP_Error('unsupported_operation_OpenRouter_logic', sprintf(__('Operation "%s" not supported for OpenRouter.', 'gpt3-ai-content-generator'), $operation)); } $full_path = $path_segment; if (!empty($api_version) && strpos($base_url, '/' . trim($api_version, '/')) === false) { $full_path = '/' . trim($api_version, '/') . $path_segment; } return $base_url . $full_path; } 